@login_required
@admin_required
def orders(request):
    orders = Order.objects.all().order_by("-created_at")
    return render(request, "admin_portal/order_list.html", {"orders": orders})

@login_required
@admin_required
def approve_payment(request, order_id: int):
    order = get_object_or_404(Order, pk=order_id)
    order.status = Order.Status.PAID
    order.save(update_fields=["status"])
    messages.success(request, f"Order #{order.id} marked as PAID.")
    return redirect("/admin-portal/orders/")

@login_required
@admin_required
def payment_settings(request):
    ps = PaymentSettings.objects.first()
    form = PaymentSettingsForm(request.POST or None, request.FILES or None, instance=ps)
    if request.method == "POST" and form.is_valid():
        form.save()
        messages.success(request, "Payment settings saved.")
        return redirect("/admin-portal/payment-settings/")
    return render(request, "admin_portal/payment_settings.html", {"form": form})
